module top_module(
    input clk,
    input rst,
    input ena,
    input [15:0] data_in,
    output reg [15:0] data_out
);reg [15:0] unused_shift_reg;

    always @(posedge clk) begin
        if (rst) begin
            unused_shift_reg <= 16'b0;
        end else if (ena) begin
            unused_shift_reg <= {unused_shift_reg[14:0], data_in[0]};
        end
    end

    assign data_out = unused_shift_reg;

endmodule
